import { useSyncExternalStore } from 'react';
import { getCueingConfigurationSnapshot, subscribeCueingConfiguration } from '../core/configure';
import type { CueingConfiguration } from '../core/ports';

export const useCueingConfiguration = (): CueingConfiguration | null =>
  useSyncExternalStore(
    subscribeCueingConfiguration,
    getCueingConfigurationSnapshot,
    getCueingConfigurationSnapshot,
  );
